import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class MyInfo extends React.Component {
    constructor(props) {
        super(props);
        this.state = { name: '', birthday: '', age: '' };
    }

    handleChange = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        });
    }

    render() {
        return (
            <div>
                <label>Name: </label>
                <input type="text" name="name" value={this.state.name} onChange={this.handleChange}/>
                <br />
                <label>Birthday: </label>
                <input type="text" name="birthday" value={this.state.birthday} onChange={this.handleChange} />
                <br />
                <label>Age: </label>
                <input type="text" name="age" value={this.state.age} onChange={this.handleChange} />
                <br />
                <Square name={this.state.name} birthday={this.state.birthday} age={this.state.age} />
            </div>
        );
    }
}

class Square extends React.Component {
    render() {
        const { name, birthday, age } = this.props;

        return (
            <div className="square">
                <h2>{name}</h2>
                <h2>{birthday} ({age})</h2>
            </div>
        );
    }
}

ReactDOM.render(
    <React.StrictMode>
        <MyInfo />
    </React.StrictMode>,
    document.getElementById('root')
);
